import{_ as t,o as a,c as s,a2 as r}from"./chunks/framework.BYlK8ftn.js";const g=JSON.parse('{"title":"Performance budget & profiling (E5.4)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/performance-budget.md","filePath":"guide/performance-budget.md","lastUpdated":1782016161000}'),o={name:"guide/performance-budget.md"};function i(n,e,d,l,c,h){return a(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="performance-budget-profiling-e5-4" tabindex="-1">Performance budget &amp; profiling (E5.4) <a class="header-anchor" href="#performance-budget-profiling-e5-4" aria-label="Permalink to &quot;Performance budget &amp; profiling (E5.4)&quot;">​</a></h1><blockquote><p>Phase 5, FLO-398. Keeps the game at <strong>60fps on mid hardware</strong>. The budget is defined as <strong>data</strong> (<code>src/game/perf/budget.ts</code>) so a profiler and unit tests can grade any frame without a GL context. Sits on top of the dense-forest work that exists to stay inside it: thin-instanced vegetation (<a href="./asset-streaming">asset-streaming.md</a>) and impostor LOD (<a href="./asset-streaming#tree-impostors-e51">asset-streaming.md</a>).</p></blockquote><h2 id="the-budget" tabindex="-1">The budget <a class="header-anchor" href="#the-budget" aria-label="Permalink to &quot;The budget&quot;">​</a></h2><p>The single hard target is <strong>60fps</strong> — a <strong>16.67ms</strong> frame. Everything else is a cheap proxy the profiler reads each frame.</p><table tabindex="0"><thead><tr><th>Metric</th><th>Limit</th><th>Why</th></tr></thead><tbody><tr><td><code>fps</code></td><td>≥ <strong>60</strong></td><td>The actual target (floor, higher is better).</td></tr><tr><td><code>frameMs</code></td><td>≤ <strong>16.67</strong></td><td>Mean frame time for 60fps.</td></tr><tr><td><code>drawCalls</code></td><td>≤ <strong>300</strong></td><td>Draw-call submission is the CPU bottleneck on the reference machine; thin-instancing keeps a dense forest well under this.</td></tr><tr><td><code>activeIndices</code></td><td>≤ <strong>3,000,000</strong></td><td>≈ 1M triangles rendered after culling + impostor LOD; bounds GPU vertex work.</td></tr></tbody></table><p>These are <strong>budgets, not hard limits</strong> — exceeding one is a signal to profile, not a crash. The constants live in <code>PERF_BUDGET</code>; tune them against real captures.</p><h3 id="mid-hardware" tabindex="-1">&quot;Mid hardware&quot; <a class="header-anchor" href="#mid-hardware" aria-label="Permalink to &quot;&quot;Mid hardware&quot;&quot;">​</a></h3><p>The reference machine is a 2019-era integrated-GPU laptop (Intel Iris / entry Apple-silicon class) running the game full-page in a browser tab. The numbers are deliberately conservative: a frame that passes on the reference machine has headroom on anything newer.</p><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  PERF_BUDGET,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  evaluateFrameBudget,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  createFrameProfiler,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  createPerfHud,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;../game/perf&#39;</span></span></code></pre></div><ul><li><strong><code>evaluateFrameBudget(metrics, budget?)</code></strong> — pure. Takes <code>{ fps, frameMs, drawCalls, activeIndices }</code>, returns a <code>BudgetReport</code> with per-metric <code>lines</code>, the failing <code>violations</code>, and a <code>withinBudget</code> boolean. fps is a floor; the rest are ceilings; a value <em>exactly</em> at the limit passes.</li><li><strong><code>createFrameProfiler(scene, opts?)</code></strong> — wraps a Babylon <code>Scene</code> with <code>SceneInstrumentation</code>, samples draw calls + frame time + active indices each frame, and grades a <strong>rolling mean</strong> (default window 60 frames ≈ 1s) so a single hitched frame doesn&#39;t flip the verdict. <code>opts.readMetrics</code> injects a metrics source — that seam is how the profiler is unit-tested under <code>NullEngine</code> (which renders nothing, so the real counters stay at 0).</li><li><strong><code>createPerfHud(parent?)</code></strong> — a dependency-free DOM overlay that renders a <code>BudgetReport</code>: one coloured row per metric (green within / red over) and a header that flips to <strong>OVER BUDGET</strong> when any line fails. Developer overlay, not the player-facing graphics-quality UI (that&#39;s E6.4).</li></ul><h2 id="profiling-tool-—-dev-perf" tabindex="-1">Profiling tool — <code>?dev=perf</code> <a class="header-anchor" href="#profiling-tool-—-dev-perf" aria-label="Permalink to &quot;Profiling tool — \`?dev=perf\`&quot;">​</a></h2><p><code>src/scenes/perfBench.ts</code> (<code>?dev=perf</code>) plants a deliberately heavy <strong>24×24 (576-tree)</strong> thin-instanced forest, attaches a <code>FrameProfiler</code> + <code>PerfHud</code>, and runs the live verdict in the corner. Fly with <strong>WASD</strong> + mouse (click to capture the pointer) and watch the metrics against their ceilings.</p><p>Open it:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://korovany.aimost.pl/?dev=perf   # or http://localhost:5173/?dev=perf</span></span></code></pre></div><p>Every second it also logs the windowed report to the console and mirrors the latest <code>{ metrics, report }</code> onto <code>window.__korovanyPerfBench</code> for smoke harnesses.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li><code>src/game/perf/budget.test.ts</code> — the pure evaluator: floor vs. ceiling semantics, exact-limit boundary, custom budgets, formatting.</li><li><code>src/game/perf/profiler.test.ts</code> — rolling-window mean, hitch smoothing, sample ageing, and the default instrumentation reader booting under <code>NullEngine</code> without throwing.</li><li><code>src/game/perf/perfHud.test.ts</code> — mount/update/dispose and the OK↔OVER header flip (jsdom).</li><li><code>src/scenes/perfBench.test.ts</code> — the bench plants the 576-tree forest, wires the profiler + HUD, samples a valid verdict, and tears the HUD out on dispose, all under <code>NullEngine</code> (no GL).</li></ul>`,18)])])}const u=t(o,[["render",i]]);export{g as __pageData,u as default};
